const main = document.getElementById('main'), container = document.getElementById('container'), maoyeedy = document.getElementById('name'), redButton = document.getElementById('red-button-placeholder'), leftPanel = document.getElementById('left'), rightPanel = document.getElementById('right'), leftTrigger = document.getElementById('left-trigger'), rightTrigger = document.getElementById('right-trigger'), circle1 = document.getElementById('circle1'), circle2 = document.getElementById('circle2'), scrollPercentage = window.innerHeight / 100 * 46;

function setColor(isGoingUp) {
    circle1.style.backgroundColor = isGoingUp ? '#93969f' : 'white', circle2.style.backgroundColor = isGoingUp ? 'white' : '#93969f';
}

function scrollMain(isGoingUp) {
    main.scrollTop += isGoingUp ? scrollPercentage : -1 * scrollPercentage, setColor(isGoingUp);
}

function toggleLeftPanel() {
    container.classList.toggle('show-left-panel');
}

function toggleRightPanel() {
    container.classList.toggle('show-right-panel');
}

function loadDeferContent() {
    document.querySelectorAll('.defer img').forEach(function (img) {
        img.src = img.dataset.src;
    });
}

circle1.addEventListener('click', function () {
    scrollMain(!1);
}), circle2.addEventListener('click', function () {
    scrollMain(!0);
}), main.addEventListener('wheel', function (event) {
    setColor(0 < event.deltaY);
}, {
    passive: !0
}), document.addEventListener('keydown', function (event) {
    'ArrowDown' === event.key || 'ArrowRight' === event.key ? scrollMain(!0) : 'ArrowUp' !== event.key && 'ArrowLeft' !== event.key || scrollMain(!1);
}), maoyeedy.addEventListener('mouseover', toggleLeftPanel), maoyeedy.addEventListener('mouseout', toggleLeftPanel),
    redButton.addEventListener('mouseover', toggleRightPanel), redButton.addEventListener('mouseout', toggleRightPanel),
    leftPanel.addEventListener('mouseover', toggleLeftPanel), leftPanel.addEventListener('mouseout', toggleLeftPanel),
    rightPanel.addEventListener('mouseover', toggleRightPanel), rightPanel.addEventListener('mouseout', toggleRightPanel),
    leftTrigger.addEventListener('mouseover', toggleLeftPanel), leftTrigger.addEventListener('mouseout', toggleLeftPanel),
    rightTrigger.addEventListener('mouseover', toggleRightPanel), rightTrigger.addEventListener('mouseout', toggleRightPanel),
    setTimeout(function () {
        loadDeferContent();
    }, 1500);